      options: [{ id: `A`, text: `Richard Serra created two large metal sculptures, <i>Open Ended</i> and <i>Strike: To Roberta and Rudy</i>.` }, { id: `B`, text: `<i>Strike: To Roberta and Rudy</i> is one of Richard Serra's large metal sculptures.` }, { id: `C`, text: `<i>Open Ended</i>, a sculpture by Richard Serra, is made of weathering steel.` }, { id: `D`, text: `<i>Open Ended</i> is made from a different kind of steel than <i>Strike: To Roberta and Rudy</i>.` }],
